package com.apollographql.apollo.api.json

import okio.Buffer
import okio.ByteString
import kotlin.contracts.ExperimentalContracts
import kotlin.contracts.InvocationKind
import kotlin.contracts.contract
import kotlin.jvm.JvmName

fun JsonWriter.writeAny(value: Any?) {
  when (value) {
    null -> nullValue()

    is Map<*, *> -> {
      writeObject {
        value.forEach { (key, value) ->
          name(key.toString())
          writeAny(value)
        }
      }
    }

    is List<*> -> {
      writeArray {
        value.forEach {
          writeAny(it)
        }
      }
    }

    is Boolean -> value(value)
    is Int -> value(value)
    is Long -> value(value)
    is Double -> value(value)
    is JsonNumber -> value(value)
    is String -> value(value)
    else -> error("Cannot write $value of class '${value::class}' to Json")
  }
}

@OptIn(ExperimentalContracts::class)
inline fun JsonWriter.writeObject(crossinline block: JsonWriter.() -> Unit) {
  contract {
    callsInPlace(block, InvocationKind.EXACTLY_ONCE)
  }

  beginObject()
  block()
  endObject()
}

@OptIn(ExperimentalContracts::class)
inline fun JsonWriter.writeArray(crossinline block: JsonWriter.() -> Unit) {
  contract {
    callsInPlace(block, InvocationKind.EXACTLY_ONCE)
  }

  beginArray()
  block()
  endArray()
}

@OptIn(ExperimentalContracts::class)
inline fun buildJsonString(indent: String? = null, crossinline block: JsonWriter.() -> Unit): String {
  contract {
    callsInPlace(block, InvocationKind.EXACTLY_ONCE)
  }

  val buffer = Buffer()
  BufferedSinkJsonWriter(buffer, indent).block()
  return buffer.readUtf8()
}

@OptIn(ExperimentalContracts::class)
inline fun buildJsonByteString(indent: String? = null, crossinline block: JsonWriter.() -> Unit): ByteString {
  contract {
    callsInPlace(block, InvocationKind.EXACTLY_ONCE)
  }

  val buffer = Buffer()
  BufferedSinkJsonWriter(buffer, indent).block()
  return buffer.readByteString()
}

@OptIn(ExperimentalContracts::class)
inline fun buildJsonMap(crossinline block: JsonWriter.() -> Unit): Any? {
  contract {
    callsInPlace(block, InvocationKind.EXACTLY_ONCE)
  }

  val writer = MapJsonWriter()
  writer.block()
  return writer.root()
}

package com.apollographql.apollo.ast

import com.apollographql.apollo.annotations.ApolloInternal
import com.apollographql.apollo.ast.Schema.Companion.NONNULL
import kotlin.reflect.KClass

// 5.5.2.3 Fragment spread is possible
internal fun GQLTypeDefinition.sharesPossibleTypesWith(other: GQLTypeDefinition, schema: Schema): Boolean {
  return schema.possibleTypes(this).intersect(schema.possibleTypes(other)).isNotEmpty()
}

fun GQLTypeDefinition.possibleTypes(schema: Schema): Set<String> {
  return schema.possibleTypes(this)
}

@ApolloInternal
fun GQLTypeDefinition.isFieldNonNull(fieldName: String, schema: Schema? = null): Boolean {
  val directive = when (this) {
    is GQLObjectTypeDefinition -> directives
    is GQLInterfaceTypeDefinition -> directives
    else -> return false
  }.firstOrNull { (schema?.originalDirectiveName(it.name) ?: it.name) == NONNULL }

  if (directive == null) {
    return false
  }

  val stringValue = (directive.arguments.first().value as GQLStringValue).value

  val selections = stringValue.parseAsGQLSelections().getOrThrow()

  return selections.filterIsInstance<GQLField>()
      .map { it.name }
      .contains(fieldName)
}

fun GQLTypeDefinition.isAbstract(): Boolean {
  return when (this) {
    is GQLUnionTypeDefinition,
    is GQLInterfaceTypeDefinition,
      -> true

    else -> false
  }
}

fun GQLTypeDefinition.isComposite(): Boolean {
  return when (this) {
    is GQLObjectTypeDefinition,
    is GQLUnionTypeDefinition,
    is GQLInterfaceTypeDefinition,
      -> true

    else -> false
  }
}

fun GQLTypeDefinition.implementsAbstractType(schema: Schema): Boolean {
  return schema.implementedTypes(name).any {
    schema.typeDefinition(it).isAbstract()
  }
}

fun GQLTypeDefinition.canHaveKeyFields(): Boolean {
  return when (this) {
    is GQLObjectTypeDefinition,
    is GQLInterfaceTypeDefinition,
      -> true

    else -> false
  }
}


internal fun KClass<out GQLTypeDefinition>.prettyName(): String {
  return when (this) {
    GQLObjectTypeDefinition::class -> "object"
    GQLInterfaceTypeDefinition::class -> "interface"
    GQLUnionTypeDefinition::class -> "union"
    GQLEnumTypeDefinition::class -> "enum"
    GQLScalarTypeDefinition::class -> "scalar"
    GQLInputValueDefinition::class -> "input object"
    else -> error("")
  }
}

package io.mockk.impl

import io.mockk.impl.MultiNotifier.Session
import java.util.concurrent.TimeUnit
import java.util.concurrent.locks.Condition
import java.util.concurrent.locks.ReentrantLock
import kotlin.concurrent.withLock

class JvmMultiNotifier : MultiNotifier {
    val lock = ReentrantLock()
    val condition: Condition = lock.newCondition()

    val conditionMet = mutableSetOf<Ref>()
    val counters = mutableMapOf<Ref, Int>()

    override fun openSession(
        keys: List<Any>,
        timeout: Long,
    ): Session {
        val start = time()
        lock.withLock {
            changeCounters(keys, 1)
        }

        return SessionImpl(start, timeout, keys)
    }

    inner class SessionImpl(
        private val start: Long,
        private val timeout: Long,
        private val keys: List<Any>,
    ) : Session {
        override fun wait(): Boolean {
            var ret = false
            lock.withLock {
                while (true) {
                    val passed = time() - start
                    if (passed >= timeout) {
                        break
                    }
                    if (checkAnyConditionsMet(keys)) {
                        ret = true
                        break
                    }
                    if (!condition.await(timeout - passed, TimeUnit.MILLISECONDS)) {
                        break
                    }
                }
            }
            return ret
        }

        override fun close() {
            lock.withLock {
                changeCounters(keys, -1)
            }
        }
    }

    private fun checkAnyConditionsMet(keys: List<Any>) = keys.any { InternalPlatform.ref(it) in conditionMet }

    private fun time() = System.currentTimeMillis()

    private fun changeCounters(
        keys: List<Any>,
        delta: Int,
    ) {
        keys.forEach {
            val ref = InternalPlatform.ref(it)
            val value = counters.getOrElse(ref) { 0 } + delta
            if (value == 0) {
                conditionMet.remove(ref)
                counters.remove(ref)
            } else {
                counters[ref] = value
            }
        }
    }

    override fun notify(key: Any) {
        lock.withLock {
            val ref = InternalPlatform.ref(key)
            if (ref in counters) {
                conditionMet.add(ref)
            }
            condition.signalAll()
        }
    }
}

package react.jsx.runtime

import js.internal.InternalApi
import js.objects.Object
import js.objects.unsafeJso
import js.reflect.Reflect.deleteProperty
import js.reflect.unsafeCast
import react.*
import react.jsx.runtime.raw.jsxRaw
import react.jsx.runtime.raw.jsxsRaw
import web.errors.reportError

@InternalApi
fun <P : Props> jsx(
    type: ElementType<P>,
): ReactElement<P> =
    jsxRaw(
        type = type,
        props = unsafeJso(),
    )

@InternalApi
fun <P : Props> jsx(
    type: ElementType<P>,
    props: P,
): ReactElement<P> =
    jsx(
        type = type,
        props = props,
        defaultKey = null,
    )

@InternalApi
fun <P : Props> jsx(
    type: ElementType<P>,
    props: P?,
    defaultKey: Key?,
): ReactElement<P> {
    if (props == null)
        return jsxRaw(
            type = type,
            props = unsafeJso(),
            key = defaultKey ?: undefined,
        )

    var finalProps = props
    val finalKey = props.key
        ?: defaultKey
        ?: undefined

    val builderChildren = props.buildChildren()
    var jsxMode = true

    if (props.key !== undefined || builderChildren != null) {
        finalProps = Object.assign(unsafeJso(), props)
        deleteProperty(finalProps, Props::key.name)

        if (builderChildren != null) {
            val container = unsafeCast<PropsWithChildren>(finalProps)
            if (container.children != null) {
                reportError(IllegalStateException("Both `children` source options used. Prop `children` will be ignored."))
            }

            val singleBuilderChild = builderChildren
                .asNodeArrayOrNull()
                ?.singleOrNull()

            jsxMode = singleBuilderChild != null

            container.children = singleBuilderChild ?: builderChildren
        }
    }

    val create = if (jsxMode) jsxRaw else jsxsRaw

    return create(
        type = type,
        props = finalProps,
        key = finalKey,
    )
}

package com.badoo.reaktive.scheduler

import android.os.Handler
import android.os.Looper
import com.badoo.reaktive.disposable.CompositeDisposable
import com.badoo.reaktive.disposable.minusAssign
import com.badoo.reaktive.disposable.plusAssign
import com.badoo.reaktive.utils.coerceAtLeastZero
import kotlin.time.Duration

internal class MainScheduler : Scheduler {

    private val disposables = CompositeDisposable()

    override fun newExecutor(): Scheduler.Executor = ExecutorImpl(disposables)

    override fun destroy() {
        disposables.dispose()
    }

    private class ExecutorImpl(
        private val disposables: CompositeDisposable
    ) : Scheduler.Executor {
        @Volatile
        private var handler: Handler? = Handler(Looper.getMainLooper())

        private val monitor = Any()
        override val isDisposed: Boolean get() = handler == null

        init {
            disposables += this
        }

        override fun dispose() {
            if (handler != null) {
                val handlerToCancel: Handler
                synchronized(monitor) {
                    handlerToCancel = handler ?: return
                    handler = null
                }
                handlerToCancel.removeCallbacksAndMessages(null)
                disposables -= this
            }
        }

        override fun submit(delay: Duration, period: Duration, task: () -> Unit) {
            val runnable =
                object : Runnable {
                    override fun run() {
                        if (!period.isInfinite()) {
                            executeIfNotRecycled {
                                it.postDelayed(this, period.coerceAtLeastZero().inWholeMilliseconds)
                            }
                        }
                        task()
                    }
                }

            executeIfNotRecycled {
                it.postDelayed(runnable, delay.coerceAtLeastZero().inWholeMilliseconds)
            }
        }

        override fun cancel() {
            executeIfNotRecycled {
                it.removeCallbacksAndMessages(null)
            }
        }

        private inline fun <T> executeIfNotRecycled(block: (Handler) -> T): T? {
            if (handler != null) {
                synchronized(monitor) {
                    return handler?.let(block)
                }
            }

            return null
        }
    }
}

package com.badoo.reaktive.scheduler

import com.badoo.reaktive.disposable.CompositeDisposable
import com.badoo.reaktive.disposable.minusAssign
import com.badoo.reaktive.disposable.plusAssign
import com.badoo.reaktive.utils.coerceAtLeastZero
import kotlin.time.Duration

internal class MainScheduler : Scheduler {

    private val disposables = CompositeDisposable()

    override fun newExecutor(): Scheduler.Executor = MainThreadExecutor(disposables)

    override fun destroy() = disposables.dispose()

    private class MainThreadExecutor(
        private val disposables: CompositeDisposable,
    ) : Scheduler.Executor {

        private var _isDisposed = false

        private val timeoutIds = mutableSetOf<TimeoutId>()
        private val intervalIds = mutableSetOf<TimeoutId>()

        init {
            disposables += this
        }

        override fun submit(delay: Duration, period: Duration, task: () -> Unit) {
            if (isDisposed) {
                return
            }

            if (period.isInfinite()) {
                setTimeout(delay = delay, task = task)
                return
            }

            if (delay.isPositive()) {
                setTimeout(delay = delay) {
                    setInterval(period = period, task)
                }
                return
            }

            setInterval(period = period, task)
        }

        private fun setTimeout(delay: Duration, task: () -> Unit) {
            var timeoutId: TimeoutId? = null

            timeoutId = jsSetTimeout(
                task = {
                    timeoutIds.remove(timeoutId)
                    task()
                },
                delayMillis = delay.coerceAtLeastZero().inWholeMilliseconds.toInt()
            )

            timeoutIds.add(timeoutId)
        }

        private fun setInterval(period: Duration, task: () -> Unit) {
            intervalIds.add(
                jsSetInterval(
                    task = task,
                    delayMillis = period.coerceAtLeastZero().inWholeMilliseconds.toInt(),
                )
            )
        }

        override fun cancel() {
            timeoutIds.forEach { jsClearTimeout(it) }
            intervalIds.forEach { jsClearInterval(it) }
        }

        override val isDisposed: Boolean
            get() = _isDisposed

        override fun dispose() {
            cancel()
            _isDisposed = true
            disposables -= this
        }
    }
}

package coil3

import coil3.EventListener.Factory
